141→export const configureModel = orgAction(
142→  z.object({
143→    sandboxId: z.string().min(1),
144→    provider: z.enum(["openai", "anthropic", "openrouter"]),
145→    apiKey: z.string().default(""),
146→    models: z.array(z.string().min(1)).min(1),
147→    defaultModel: z.string().min(1),
148→  }),
149→  async ({ organizationId }, input) => {
150→    const runtime = await getSandboxRuntime(input.sandboxId, organizationId);
151→
152→    // Step 1: Register provider via onboard (only if API key provided)
153→    if (input.apiKey) {
154→      const onboardCmd = buildOnboardCmd(input.provider, input.apiKey);
155→      await runOrThrow(
156→        runtime,
157→        onboardCmd,
158→        "onboard",
159→        onboardCmd.replace(esc(input.apiKey), "'***'"),
160→      );
161→    }
162→
163→    // Step 2: Read existing models record and merge with new models
164→    let existing: Record<string, { alias?: string }> = {};
165→    try {
166→      const getResult = await runOrThrow(
167→        runtime,
168→        `openclaw config get agents.defaults.models --json`,
169→        "getAllowlist",
170→      );
171→      const parsed = JSON.parse(getResult.stdout.trim() || "{}");
172→      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
173→        existing = parsed as Record<string, { alias?: string }>;
174→      }
175→    } catch {
176→      // No existing allowlist — start fresh
177→    }
178→
179→    // Add new models (preserve existing entries)
180→    for (const modelId of input.models) {
181→      if (!existing[modelId]) {
182→        const parts = modelId.split("/");
183→        existing[modelId] = { alias: parts[parts.length - 1] };
184→      }
185→    }
186→
187→    const allowCmd = `openclaw config set agents.defaults.models ${esc(JSON.stringify(existing))}`;
188→    await runOrThrow(runtime, allowCmd, "setAllowlist");
189→
190→    // Step 3: Set the default model via config (avoids provider auth validation)
191→    const setCmd = `openclaw config set agents.defaults.model.primary ${esc(input.defaultModel)}`;
192→    await runOrThrow(runtime, setCmd, "setDefault");
193→
194→    // Step 4: Restart gateway to pick up new config
195→    try {
196→      await runOrThrow(runtime, `openclaw gateway restart`, "gatewayRestart");
197→    } catch {
198→      // Gateway restart may throw — safe to ignore
199→    }
200→
201→    return { success: true };
202→  },
203→);
