 5→export const E2B_TEMPLATE_NAME = "runagents-dev-20260227";
 6→export const E2B_TIMEOUT_MS = 120_000;
 7→
 8→export function getE2BApiKey(): string {
 9→  if (!env.E2B_API_KEY) throw new Error("E2B_API_KEY is not configured");
10→  return env.E2B_API_KEY;
11→}
